window.onload = () => {
  const duration = 3500; // 7 seconds until everything ends
  const boxes = document.querySelectorAll(".counter-box");

  // Fade + Slide animation trigger
  boxes.forEach((box, index) => {
    setTimeout(() => {
      box.classList.add("show");
    }, index * 200); // staggered entry (optional)
  });

  // Counter start
const stats = getStats();
counterUp("animeCount", stats.animeCount, duration);  
  counterUp("seasonCount", 348, duration);
  counterUp("episodeCount", 6178, duration);
};

// === TOPBAR MENU & SEARCH ===
const menuBtn = document.getElementById('menuBtn');
const sideMenu = document.getElementById('sideMenu');
const menuOverlay = document.getElementById('menuOverlay');
const topSearchBtn = document.getElementById('topSearchBtn');

function openMenu() {
  if(sideMenu) sideMenu.classList.add('open');
  if(menuOverlay) menuOverlay.classList.add('open');
}
function closeMenu() {
  if(sideMenu) sideMenu.classList.remove('open');
  if(menuOverlay) menuOverlay.classList.remove('open');
}

if(menuBtn) {
  menuBtn.onclick = () => {
    sideMenu && sideMenu.classList.contains('open') ? closeMenu() : openMenu();
  };
}

if(topSearchBtn) {
  topSearchBtn.onclick = (e) => {
    e.preventDefault();
    const box = document.getElementById('searchBox');
    if(box) {
      const topOffset = 80;
      const elementPosition = box.getBoundingClientRect().top + window.pageYOffset;
      const offsetPosition = elementPosition - topOffset;
      
      window.scrollTo({
        top: offsetPosition,
        behavior: 'smooth'
      });
      
      setTimeout(()=>box.focus(), 500);
    }
  };
}

if(menuOverlay) menuOverlay.onclick = closeMenu;

// === 1. Data & Order (kept as before) ===
function filterTopFive(genre) {
  var container = document.getElementById('topFiveResults');
  if (!container) return;
  var ids = TOP_5_DATA[genre];
  if (!ids) { container.innerHTML = ''; return; }

  var tabs = document.querySelectorAll('#topFiveDropdown .body-dropdown-container a');
  for (var i = 0; i < tabs.length; i++) tabs[i].classList.remove('topfive-active');
  var activeTab = document.querySelector('#topFiveDropdown .body-dropdown-container a[onclick*="' + genre + '"]');
  if (activeTab) activeTab.classList.add('topfive-active');

  container.innerHTML = '';
  var allCards = document.querySelectorAll('#grid .card');
  for (var j = 0; j < ids.length; j++) {
    var target = null;
    for (var k = 0; k < allCards.length; k++) {
      var badge = allCards[k].querySelector('.badge');
      if (badge && parseInt(badge.textContent.replace(/\D/g, '')) === ids[j]) {
        target = allCards[k].cloneNode(true);
        break;
      }
    }
    if (target) {
      target.removeAttribute('style');
      var badge = target.querySelector('.badge');
      if (badge) badge.textContent = 'Top-' + (j + 1);
      container.appendChild(target);
    }
  }
}

